import React from 'react';
import { sanitizeHtml } from 'sanitize-html';

const Bio = ({ bio }) => {
  const sanitizedBio = sanitizeHtml(bio, {
    allowedTags: ['p', 'strong', 'em', 'br'],
    allowedAttributes: ['href'],
  });

  return (
    <div dangerouslySetInnerHTML={{ __html: sanitizedBio }} />
  );
};

export default Bio;